<div class="stats-grid"><div class="stat-card primary"><span>Total Users</span><h2><?= (int)$counts['total_users'] ?></h2></div><div class="stat-card"><span>Active Users</span><h2><?= (int)$counts['active_users'] ?></h2></div><div class="stat-card"><span>Total Transactions</span><h2><?= (int)$stats['total_transactions'] ?></h2></div><div class="stat-card"><span>Wallet Activity</span><h2><?= money((float)$stats['wallet_activity']) ?></h2></div></div><div class="grid-2 section-gap"><div class="card"><div class="card-head"><h3>Recent Transactions</h3></div><div class="table-wrap"><table><thead><tr><th>Ref</th><th>User</th><th>Type</th><th>Amount</th></tr></thead><tbody><?php foreach ($recentTransactions as $tx): ?><tr><td><?= e($tx['reference_no']) ?></td><td><?= e($tx['name']) ?></td><td><?= e($tx['type']) ?></td><td><?= money((float)$tx['amount']) ?></td></tr><?php endforeach; ?></tbody></table></div></div><div class="card"><div class="card-head"><h3>Activity by Day</h3></div><div class="chart-list"><?php foreach ($dailySummary as $day): ?><div class="chart-row"><span><?= e($day['day']) ?></span><div class="chart-bar"><span style="width: <?= min(100, max(5, (float)$day['total_amount'] / 10)) ?>%"></span></div><strong><?= money((float)$day['total_amount']) ?></strong></div><?php endforeach; ?></div></div></div>
